async function evaluate(draft: string, context: HarnessContext): Promise<{ valid: boolean, feedback: string[] }> {
  const feedback: string[] = [];
  let valid = true;

  const keywordsToUse = context.customTensionKeywords && context.customTensionKeywords.length > 0
    ? context.customTensionKeywords
    : defaultTensionKeywords;

  const minTensionKeywords = context.minTensionKeywords !== undefined
    ? context.minTensionKeywords
    : 3; // Default minimum

  const lowerCaseDraft = draft.toLowerCase();
  let tensionKeywordCount = 0;
  const foundKeywords: Set<string> = new Set();

  for (const keyword of keywordsToUse) {
    const regex = new RegExp(`\\b${keyword}\\b`, 'gi'); // Whole word match, case-insensitive
    let match;
    while ((match = regex.exec(lowerCaseDraft)) !== null) {
      tensionKeywordCount++;
      foundKeywords.add(keyword);
    }
  }

  if (draft.trim().length === 0) {
    feedback.push("The draft is empty. No tension can be evaluated.");
    valid = false;
  } else if (tensionKeywordCount < minTensionKeywords) {
    feedback.push(`The draft appears to lack significant tension. Only ${tensionKeywordCount} tension-related keywords were found (expected at least ${minTensionKeywords}).`);
    valid = false;
  } else if (tensionKeywordCount >= minTensionKeywords && tensionKeywordCount < minTensionKeywords + 4) { // A small buffer for "moderate"
    feedback.push(`Moderate tension detected. ${tensionKeywordCount} tension-related keywords were found. Consider amplifying tension in key areas.`);
    valid = true;
  } else {
    feedback.push(`Strong tension detected! ${tensionKeywordCount} tension-related keywords were found, indicating a compelling narrative. Keep up the great work!`);
    valid = true;
  }

  if (foundKeywords.size > 0) {
    feedback.push(`Found specific tension keywords: ${Array.from(foundKeywords).join(', ')}.`);
  } else if (tensionKeywordCount > 0) {
    // This case should ideally not happen if tensionKeywordCount > 0, but as a fallback
    feedback.push(`Some tension was detected, but no specific keywords were identified from the provided list.`);
  }

  // Optional: Genre-specific advice (example)
  if (context.genre) {
    const genre = context.genre.toLowerCase();
    if (genre === "thriller" || genre === "horror") {
      if (tensionKeywordCount < minTensionKeywords + 5) { // Higher expectation for these genres
        feedback.push(`For a ${genre} narrative, the current level of tension might be insufficient. Aim for more sustained suspense and conflict.`);
        valid = false; // Re-evaluate validity based on genre expectation
      }
    } else if (genre === "romance" || genre === "slice of life") {
      if (tensionKeywordCount > minTensionKeywords + 5) {
        feedback.push(`For a ${genre} narrative, the current level of tension might be too high. Consider balancing with moments of calm or emotional connection.`);
      }
    }
  }

  return { valid, feedback };
}

